1	'use strict';
2	/**
3	 * GSD-T Token Capture Wrapper (M41 D1)
4	 *
5	 * Single reusable module every GSD-T spawn call site uses. Parses the
6	 * `usage` envelope from Claude's result frame, appends a row to
7	 * `.gsd-t/token-log.md`, and appends a schema-v1 JSONL record to
8	 * `.gsd-t/metrics/token-usage.jsonl`.
9	 *
10	 * Zero external deps. `.cjs` so it loads in both ESM-default projects
11	 * and CJS projects without transpilation.
12	 *
13	 * Contracts:
14	 *   - .gsd-t/contracts/metrics-schema-contract.md (schema v1)
15	 *   - .gsd-t/contracts/stream-json-sink-contract.md v1.1.0 (usage semantics)
16	 *
17	 * Missing `usage` → write `—` in Tokens column. Never `0`, never `N/A`.
18	 */
19	
20	const fs = require('fs');
21	const path = require('path');
22	
23	const SCHEMA_VERSION = 2;
24	
25	const NEW_HEADER = '| Datetime-start | Datetime-end | Command | Step | Model | Duration(s) | Tokens | Notes | Domain | Task | Ctx% |';
26	const NEW_SEP    = '|---|---|---|---|---|---|---|---|---|---|---|';
27	
28	function pad2(n) { return String(n).padStart(2, '0'); }
29	function fmtDateTime(d) {
30	  return `${d.getFullYear()}-${pad2(d.getMonth()+1)}-${pad2(d.getDate())} ${pad2(d.getHours())}:${pad2(d.getMinutes())}`;
31	}
32	
33	function _parseUsageFromResult(result) {
34	  if (!result || typeof result !== 'object') return undefined;
35	  if (result.usage && typeof result.usage === 'object') return result.usage;
36	  if (result.result && typeof result.result === 'object' && result.result.usage && typeof result.result.usage === 'object') {
37	    return result.result.usage;
38	  }
39	  return undefined;
40	}
41	
42	function _formatTokensCell(usage) {
43	  if (!usage || typeof usage !== 'object') return '—';
44	  const inp = Number(usage.input_tokens || 0);
45	  const out = Number(usage.output_tokens || 0);
46	  const cr  = Number(usage.cache_read_input_tokens || 0);
47	  const cc  = Number(usage.cache_creation_input_tokens || 0);
48	  const costNum = (typeof usage.total_cost_usd === 'number') ? usage.total_cost_usd : (typeof usage.cost_usd === 'number' ? usage.cost_usd : null);
49	  const cost = (costNum == null) ? '—' : `$${costNum.toFixed(2)}`;
50	  if (!inp && !out && !cr && !cc && cost === '—') return '—';
51	  return `in=${inp} out=${out} cr=${cr} cc=${cc} ${cost}`;
52	}
53	
54	function _ensureDir(p) {
55	  const dir = path.dirname(p);
56	  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
57	}
58	
59	function _ensureTokenLogHeader(tokenLogPath) {
60	  if (!fs.existsSync(tokenLogPath)) {
61	    _ensureDir(tokenLogPath);
62	    fs.writeFileSync(tokenLogPath, `# GSD-T Token Log\n\n${NEW_HEADER}\n${NEW_SEP}\n`);
63	    return;
64	  }
65	  const text = fs.readFileSync(tokenLogPath, 'utf8');
66	  if (text.includes(NEW_HEADER)) return;
67	  // Old header detection: first header line that starts with `| Datetime-start`
68	  const lines = text.split('\n');
69	  const headerIdx = lines.findIndex(l => /^\|\s*Datetime-start\s*\|/.test(l));
70	  if (headerIdx < 0) {
71	    // No header at all — append new one
72	    fs.writeFileSync(tokenLogPath, text.trimEnd() + `\n\n${NEW_HEADER}\n${NEW_SEP}\n`);
73	    return;
74	  }
75	  // Replace old header + separator with new header + separator, preserve existing rows
76	  const sepIdx = headerIdx + 1;
77	  lines[headerIdx] = NEW_HEADER;
78	  if (lines[sepIdx] && /^\|[\s\-|]+\|$/.test(lines[sepIdx])) {
79	    lines[sepIdx] = NEW_SEP;
80	  } else {
81	    lines.splice(sepIdx, 0, NEW_SEP);
82	  }
83	  fs.writeFileSync(tokenLogPath, lines.join('\n'));
84	}
85	
86	function _appendTokenLogRow(tokenLogPath, row) {
87	  _ensureTokenLogHeader(tokenLogPath);
88	  const line = `| ${row.startedAt} | ${row.endedAt} | ${row.command} | ${row.step} | ${row.model} | ${row.durationSec}s | ${row.tokensCell} | ${row.notes} | ${row.domain} | ${row.task} | ${row.ctxPct} |\n`;
89	  fs.appendFileSync(tokenLogPath, line);
90	}
91	
92	function _appendJsonlRecord(jsonlPath, record) {
93	  _ensureDir(jsonlPath);
94	  fs.appendFileSync(jsonlPath, JSON.stringify(record) + '\n');
95	}
96	
97	function _buildJsonlRecord({ command, step, model, startedAt, endedAt, durationSec, usage, domain, task, notes, ctxPct, milestone, source, sessionId, turnId, sessionType, toolAttribution, compactionPressure, cw_id }) {
98	  const u = usage || {};
99	  const cost = (typeof u.total_cost_usd === 'number') ? u.total_cost_usd : (typeof u.cost_usd === 'number' ? u.cost_usd : null);
100	  const rec = {
101	    schemaVersion: SCHEMA_VERSION,
102	    ts: new Date().toISOString(),
103	    source: source || 'live',
104	    command,
105	    step,
106	    model,
107	    startedAt,
108	    endedAt,
109	    durationMs: durationSec * 1000,
110	    inputTokens: Number(u.input_tokens || 0),
111	    outputTokens: Number(u.output_tokens || 0),
112	    cacheReadInputTokens: Number(u.cache_read_input_tokens || 0),
113	    cacheCreationInputTokens: Number(u.cache_creation_input_tokens || 0),
114	    costUSD: cost,
115	    domain: domain || null,
116	    task: task || null,
117	    milestone: milestone || null,
118	    ctxPct: ctxPct == null ? null : ctxPct,
119	    notes: notes || null,
120	    hasUsage: !!usage,
121	  };
122	  if (sessionId != null)  rec.session_id  = String(sessionId);
123	  if (turnId != null)     rec.turn_id     = String(turnId);
124	  if (sessionType != null) rec.sessionType = sessionType;
125	  if (Array.isArray(toolAttribution) && toolAttribution.length) rec.tool_attribution = toolAttribution;
126	  if (compactionPressure && typeof compactionPressure === 'object') rec.compaction_pressure = compactionPressure;
127	  // M44 D7 v2.1.0: optional per-Context-Window attribution key.
128	  // Omitted (not null, not "") when the caller does not supply it, so
129	  // pre-D7 callers continue to produce byte-identical rows.
130	  if (cw_id != null && cw_id !== '') rec.cw_id = String(cw_id);
131	  return rec;
132	}
133	
134	function _inferMilestone(projectDir) {
135	  try {
136	    const progress = fs.readFileSync(path.join(projectDir, '.gsd-t', 'progress.md'), 'utf8');
137	    const m = /\*\*(M\d+)\b/.exec(progress) || /## Status:\s*(M\d+)/.exec(progress);
138	    return m ? m[1] : null;
139	  } catch (_) { return null; }
140	}
141	
142	function _resolveCtxPct(projectDir) {
143	  try {
144	    const tb = require('./token-budget.cjs');
145	    const s = tb.getSessionStatus(projectDir);
146	    return (s && typeof s.pct === 'number') ? s.pct : (s && s.pct) || 'N/A';
147	  } catch (_) { return 'N/A'; }
148	}
149	
150	function _parseStartedAt(s) {
151	  if (!s) return Date.now();
152	  if (/^\d{4}-\d{2}-\d{2} \d{2}:\d{2}$/.test(s)) {
153	    const [d, t] = s.split(' ');
154	    return new Date(`${d}T${t}:00`).getTime();
155	  }
156	  const parsed = Date.parse(s);
157	  return Number.isFinite(parsed) ? parsed : Date.now();
158	}
159	
160	/**
161	 * Record a single spawn row to both token-log.md and token-usage.jsonl.
162	 *
163	 * @param {object} opts
164	 * @param {string} opts.projectDir
165	 * @param {string} opts.command        e.g. 'gsd-t-execute'
166	 * @param {string} opts.step           e.g. 'Step 4'
167	 * @param {string} opts.model          e.g. 'sonnet'
168	 * @param {string} opts.startedAt      'YYYY-MM-DD HH:MM'
169	 * @param {string} opts.endedAt        'YYYY-MM-DD HH:MM'
170	 * @param {object} [opts.usage]        Claude usage envelope; undefined → '—'
171	 * @param {string} [opts.domain]
172	 * @param {string} [opts.task]
173	 * @param {string|number} [opts.ctxPct]
174	 * @param {string} [opts.notes]
175	 * @param {'live'|'backfill'} [opts.source]
176	 * @param {string} [opts.sessionId]          v2 — stable session identifier
177	 * @param {string|number} [opts.turnId]      v2 — per-turn identifier within sessionId
178	 * @param {'in-session'|'headless'} [opts.sessionType]  v2 — channel classifier
179	 * @param {Array}  [opts.toolAttribution]    v2 — D2 joiner output; usually omitted by spawn callers
180	 * @param {object} [opts.compactionPressure] v2 — D5 runway snapshot; usually omitted by spawn callers
181	 * @param {string} [opts.cw_id]              v2.1.0 — per-Context-Window attribution key (M44 D7).
182	 *                                            Pass-through only; the wrapper does not derive it.
183	 *                                            Omitted from the row when absent (NOT null, NOT "").
184	 * @returns {{tokenLogPath: string, jsonlPath: string}}
185	 */
186	function recordSpawnRow(opts) {
187	  const projectDir = opts.projectDir || '.';
188	  const tokenLogPath = opts.tokenLogPath || path.join(projectDir, '.gsd-t', 'token-log.md');
189	  const jsonlPath   = opts.jsonlPath   || path.join(projectDir, '.gsd-t', 'metrics', 'token-usage.jsonl');
190	
191	  const startMs = _parseStartedAt(opts.startedAt);
192	  const endMs   = _parseStartedAt(opts.endedAt);
193	  const durationSec = Math.max(0, Math.round((endMs - startMs) / 1000));
194	
195	  const tokensCell = _formatTokensCell(opts.usage);
196	  const notes = (opts.notes == null || opts.notes === '') ? '-' : String(opts.notes).replace(/\|/g, '\\|');
197	  const domain = (opts.domain == null || opts.domain === '') ? '-' : String(opts.domain);
198	  const task   = (opts.task   == null || opts.task   === '') ? '-' : String(opts.task);
199	  const ctxPct = (opts.ctxPct == null) ? 'N/A' : String(opts.ctxPct);
200	
201	  // skipMarkdownLog: JSONL is canonical (D3). The markdown log is a legacy view
202	  // kept in sync for human-readable tailing; high-frequency producers (D1
203	  // per-turn in-session rows, D2 joiner) should write JSONL-only and rely on
204	  // `gsd-t tokens --regenerate-log` for the markdown rendering.
205	  if (!opts.skipMarkdownLog) {
206	    _appendTokenLogRow(tokenLogPath, {
207	      startedAt: opts.startedAt,
208	      endedAt: opts.endedAt,
209	      command: opts.command,
210	      step: opts.step,
211	      model: opts.model,
212	      durationSec,
213	      tokensCell,
214	      notes,
215	      domain,
216	      task,
217	      ctxPct,
218	    });
219	  }
220	
221	  const milestone = opts.milestone || _inferMilestone(projectDir);
222	  _appendJsonlRecord(jsonlPath, _buildJsonlRecord({
223	    command: opts.command,
224	    step: opts.step,
225	    model: opts.model,
226	    startedAt: opts.startedAt,
227	    endedAt: opts.endedAt,
228	    durationSec,
229	    usage: opts.usage,
230	    domain: opts.domain || null,
231	    task: opts.task || null,
232	    notes: opts.notes || null,
233	    ctxPct: opts.ctxPct == null ? null : opts.ctxPct,
234	    milestone,
235	    source: opts.source || 'live',
236	    sessionId: opts.sessionId,
237	    turnId: opts.turnId,
238	    sessionType: opts.sessionType,
239	    toolAttribution: opts.toolAttribution,
240	    compactionPressure: opts.compactionPressure,
241	    cw_id: opts.cw_id,
242	  }));
243	
244	  return { tokenLogPath, jsonlPath };
245	}
246	
247	/**
248	 * Wrap an async spawn callable; capture timing + usage + write the row.
249	 *
250	 * @param {object} opts
251	 * @param {string} opts.command
252	 * @param {string} opts.step
253	 * @param {string} opts.model
254	 * @param {string} opts.description
255	 * @param {string} [opts.projectDir='.']
256	 * @param {() => Promise<any>} opts.spawnFn
257	 * @param {string} [opts.domain]
258	 * @param {string} [opts.task]
259	 * @returns {Promise<{result: any, usage: any|undefined, rowWritten: {tokenLogPath, jsonlPath}}>}
260	 */
261	async function captureSpawn(opts) {
262	  if (!opts || typeof opts.spawnFn !== 'function') {
263	    throw new Error('captureSpawn: spawnFn is required and must be a function');
264	  }
265	  const projectDir = opts.projectDir || '.';
266	  const startDate = new Date();
267	  const startedAt = fmtDateTime(startDate);
268	  const startMs = startDate.getTime();
269	
270	  // Visible banner before the spawn fires
271	  process.stdout.write(`⚙ [${opts.model}] ${opts.command} → ${opts.description}\n`);
272	
273	  let result, caught;
274	  try {
275	    result = await opts.spawnFn();
276	  } catch (err) {
277	    caught = err;
278	  }
279	
280	  const endDate = new Date();
281	  const endedAt = fmtDateTime(endDate);
282	
283	  const usage = caught ? undefined : _parseUsageFromResult(result);
284	  const ctxPct = _resolveCtxPct(projectDir);
285	  const notes = caught ? `spawn_error: ${String(caught && caught.message || caught).slice(0, 200)}` : (opts.notes || '-');
286	
287	  const rowWritten = recordSpawnRow({
288	    projectDir,
289	    command: opts.command,
290	    step: opts.step,
291	    model: opts.model,
292	    startedAt,
293	    endedAt,
294	    usage,
295	    domain: opts.domain,
296	    task: opts.task,
297	    ctxPct,
298	    notes,
299	    sessionId: opts.sessionId,
300	    turnId: opts.turnId,
301	    sessionType: opts.sessionType,
302	    toolAttribution: opts.toolAttribution,
303	    compactionPressure: opts.compactionPressure,
304	    cw_id: opts.cw_id,
305	  });
306	
307	  if (caught) throw caught;
308	  return { result, usage, rowWritten };
309	}
310	
311	module.exports = {
312	  captureSpawn,
313	  recordSpawnRow,
314	  _parseUsageFromResult,
315	  _formatTokensCell,
316	  _ensureTokenLogHeader,
317	  _buildJsonlRecord,
318	  SCHEMA_VERSION,
319	  NEW_HEADER,
320	  NEW_SEP,
321	};
322

