 * @param {string} [opts.teeDir]
 * @param {string} [opts.projectDir]
 * @param {string} [opts.command='parallel-cli']
 * @param {string} [opts.step='parallel']
 * @param {string} [opts.domain='-']
 * @param {string} [opts.task='-']
